task.spawn(function()
    for i=1,TOTAL do
        local ok,err=pcall(function()
            local fn="px_yt_iZQEJ3l8Mo8_64_1780623516_"..i..".png"
            if not isfile(fn) then
                local data=game:HttpGet(_frameUrls[i])
                writefile(fn,data)
            end
            local img=Instance.new("ImageLabel")
            img.Size=UDim2.new(1,0,1,0)
            img.Image=getcustomasset(fn)
            img.ScaleType=Enum.ScaleType.Fit
            img.BackgroundTransparency=1
            img.Visible=false
            img.ZIndex=2
            img.Parent=vp
            _images[i]=img
            _loadedFlags[i]=true
            loadedCount=loadedCount+1
        end)
        if not ok then
            warn("Erro no frame "..i..": "..tostring(err))
            loadedCount=loadedCount+1
        end
        loadingLbl.Text="Carregando... "..loadedCount.."/2189"
        loadingBarFill.Size=UDim2.new(loadedCount/TOTAL,0,1,0)
        task.wait()
    end
    loadingDone=true
    loadingBg.Visible=false
    loadingLbl.Visible=false
    loadingBarBg.Visible=false
    if _images[1] then _images[1].Visible=true end
    playing=true
    lastFT=tick()
    _startAudio()
end)

